function responseText(resp) {
  if (typeof resp.output_text === 'string') return resp.output_text;
  if (!Array.isArray(resp.output)) return '';
  return resp.output.map((item) => {
    if (!Array.isArray(item.content)) return '';
    return item.content.map((c) => c.text || c.output_text || '').join('');
  }).join('');
}

function parseLooseJson(text) {
  const cleaned = String(text || '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const start = cleaned.indexOf('{');
    const end = cleaned.lastIndexOf('}');
    if (start >= 0 && end > start) return JSON.parse(cleaned.slice(start, end + 1));
    throw error;
  }
}

const cfg = $node['初始化配置'].json;
const rawText = responseText($json);
const parsed = parseLooseJson(rawText);
const topics = Array.isArray(parsed.topics) ? parsed.topics : [];
if (topics.length === 0) throw new Error('OpenAI没有返回topics数组，请打开上一个节点查看原始输出。');

const normalized = topics.map((topic, index) => ({
  rank: index + 1,
  topic: topic.topic || topic['选题'] || '',
  angle: topic.angle || topic['切入角度'] || '',
  target_audience: topic.target_audience || topic['目标观众'] || '',
  why_now: topic.why_now || topic['为什么现在发'] || '',
  score: Number(topic.score || topic['评分'] || 0),
  risk_note: topic.risk_note || topic['风险提示'] || '',
  search_keywords: Array.isArray(topic.search_keywords) ? topic.search_keywords : [],
  source_links: Array.isArray(topic.source_links) ? topic.source_links : []
}));

normalized.sort((a, b) => b.score - a.score);
const selected = normalized[0];
return [{
  json: {
    ...cfg,
    topics: normalized,
    selected_topic: selected,
    topic_count: normalized.length,
    source_links: selected.source_links || []
  }
}];

