const forbidden = /(微信|weixin|wechat|vx|v信|手机号|电话|QQ|QQ群|邮箱|email|Telegram|WhatsApp|加我|进群|私信领资料|扫码)/i;
const selected = $node['选择评分最高选题'].json;
const parsed = parseLooseJson(responseText($json));
const joined = JSON.stringify(parsed);
const hasForbiddenContact = forbidden.test(joined);
const facts = Array.isArray(parsed.facts) ? parsed.facts : [];
const sourceLinks = facts.map((fact) => fact.source_url).filter(Boolean);
const selectedSources = (selected.source_links || []).map((s) => s.url).filter(Boolean);
const allSources = Array.from(new Set([...sourceLinks, ...selectedSources]));
const keywords = Array.isArray(parsed.material_keywords) && parsed.material_keywords.length > 0
  ? parsed.material_keywords
  : (selected.selected_topic.search_keywords || ['artificial intelligence technology']);
const scriptId = parsed.script_id || selected.run_id;

return [{
  json: {
    ...selected,
    script_id: scriptId,
    script: parsed,
    voiceover: parsed.voiceover || '',
    subtitle_text: parsed.subtitle_text || '',
    subtitle_blocks: Array.isArray(parsed.subtitle_blocks) ? parsed.subtitle_blocks : [],
    titles: Array.isArray(parsed.titles) ? parsed.titles : [],
    cover_text: parsed.cover_text || '',
    comment_guide: parsed.comment_guide || '',
    storyboard: Array.isArray(parsed.storyboard) ? parsed.storyboard : [],
    material_keywords: keywords,
    search_query: keywords[0] || 'artificial intelligence technology',
    facts,
    all_source_links: allSources,
    compliance: {
      has_forbidden_contact: hasForbiddenContact,
      source_count: allSources.length,
      manual_review_required: true,
      status: hasForbiddenContact || allSources.length < 2 ? '需要人工修改' : '待人工审核'
    }
  }
}];

const base = $node['解析脚本并合规检查'].json;
const pexels = $node['Pexels 搜索授权视频'].json || {};
const pixabay = $node['Pixabay 搜索授权视频'].json || {};

function choosePexelsVideo(data) {
  const videos = Array.isArray(data.videos) ? data.videos : [];
  if (!videos.length) return null;
  const video = videos[0];
  const files = Array.isArray(video.video_files) ? video.video_files : [];
  const mp4s = files.filter((f) => String(f.file_type || '').includes('mp4') || String(f.link || '').includes('.mp4'));
  const sorted = mp4s.sort((a, b) => (b.height || 0) - (a.height || 0));
  const file = sorted.find((f) => (f.height || 0) >= 1280) || sorted[0] || files[0];
  if (!file || !file.link) return null;
  return {
    platform: 'Pexels',
    asset_id: String(video.id || ''),
    asset_type: 'video',
    page_url: video.url || '',
    download_url: file.link,
    author: video.user && video.user.name ? video.user.name : '',
    author_url: video.user && video.user.url ? video.user.url : '',
    license_url: 'https://www.pexels.com/license/',
    search_keyword: base.search_query
  };
}

function choosePixabayVideo(data) {
  const hits = Array.isArray(data.hits) ? data.hits : [];
  if (!hits.length) return null;
  const hit = hits[0];
  const variants = hit.videos || {};
  const selected = variants.large || variants.medium || variants.small || variants.tiny || {};
  if (!selected.url) return null;
  return {
    platform: 'Pixabay',
    asset_id: String(hit.id || ''),
    asset_type: 'video',
    page_url: hit.pageURL || '',
    download_url: selected.url,
    author: hit.user || '',
    author_url: hit.user_id ? 'https://pixabay.com/users/' + hit.user + '-' + hit.user_id + '/' : '',
    license_url: 'https://pixabay.com/service/license-summary/',
    search_keyword: base.search_query
  };
}

const material = choosePexelsVideo(pexels) || choosePixabayVideo(pixabay);
return [{
  json: {
    ...base,
    material: material || {
      platform: '',
      asset_id: '',
      asset_type: 'video',
      page_url: '',
      download_url: '',
      author: '',
      author_url: '',
      license_url: '',
      search_keyword: base.search_query
    },
    material_status: material ? '素材已找到' : '素材未找到'
  }
}];

const base = $node['选择授权素材'].json;
const cloudinary = $node['上传配音到 Cloudinary'].json || {};
const audioUrl = cloudinary.secure_url || cloudinary.url || '';
const material = base.material || {};
const blocks = Array.isArray(base.subtitle_blocks) && base.subtitle_blocks.length
  ? base.subtitle_blocks
  : [{ start: 0, end: 60, text: base.subtitle_text || base.voiceover || '' }];

const subtitleElements = blocks.slice(0, 12).map((block) => ({
  type: 'text',
  time: Number(block.start || 0),
  duration: Math.max(2, Number(block.end || 0) - Number(block.start || 0) || 5),
  text: String(block.text || '').slice(0, 80),
  x: '50%',
  y: '82%',
  width: '88%',
  height: '16%',
  fill_color: '#ffffff',
  font_size: 46,
  font_weight: '700',
  text_align: 'center',
  stroke_color: '#000000',
  stroke_width: 2
}));

const renderScript = {
  output_format: 'mp4',
  width: 1080,
  height: 1920,
  duration: 60,
  frame_rate: 30,
  elements: [
    {
      type: 'video',
      source: material.download_url,
      duration: 60,
      width: '100%',
      height: '100%',
      fit: 'cover'
    },
    {
      type: 'audio',
      source: audioUrl
    },
    {
      type: 'text',
      time: 0,
      duration: 4,
      text: base.cover_text || (base.titles[0] || base.selected_topic.topic || '').slice(0, 18),
      x: '50%',
      y: '18%',
      width: '86%',
      height: '18%',
      fill_color: '#ffffff',
      font_size: 72,
      font_weight: '800',
      text_align: 'center',
      stroke_color: '#000000',
      stroke_width: 3
    },
    ...subtitleElements
  ]
};

return [{
  json: {
    ...base,
    audio_public_url: audioUrl,
    tts_status: audioUrl ? '配音完成' : '配音上传失败',
    render_script: renderScript
  }
}];

const base = $node['准备 Creatomate RenderScript'].json;
const submitted = $node['Creatomate 合成竖版视频'].json || {};
const statusResponse = $node['Creatomate 查询渲染状态'].json || {};
const submitRender = Array.isArray(submitted) ? submitted[0] : submitted;
const statusRender = Array.isArray(statusResponse) ? statusResponse[0] : statusResponse;
const render = statusRender && statusRender.id ? statusRender : submitRender;
const titles = base.titles || [];
const videoStatus = render.status === 'succeeded' ? '待人工审核' : (render.status || 'render_submitted');
const reviewStatus = base.compliance && base.compliance.status ? base.compliance.status : '待人工审核';
const remarks = [];
if (base.compliance && base.compliance.has_forbidden_contact) remarks.push('合规检查发现疑似站外联系方式，请人工修改。');
if (base.compliance && base.compliance.source_count < 2) remarks.push('事实来源少于2条，请人工补充来源。');
if (base.material_status !== '素材已找到') remarks.push('授权素材未找到，请人工补充。');
if (render.status && render.status !== 'succeeded') remarks.push('Creatomate当前状态：' + render.status + '，如果仍在渲染请稍后手动查看。');
if (render.error_message) remarks.push('Creatomate错误：' + render.error_message);

return [{
  json: {
    script_id: base.script_id,
    date: base.run_date,
    topic: base.selected_topic.topic,
    angle: base.selected_topic.angle,
    target_audience: base.selected_topic.target_audience,
    score: base.selected_topic.score,
    voiceover: base.voiceover,
    subtitle_text: base.subtitle_text,
    title_1: titles[0] || '',
    title_2: titles[1] || '',
    title_3: titles[2] || '',
    cover_text: base.cover_text,
    comment_guide: base.comment_guide,
    storyboard: JSON.stringify(base.storyboard || []),
    source_links: (base.all_source_links || []).join('\n'),
    facts: JSON.stringify(base.facts || []),
    material_platform: base.material.platform,
    material_asset_id: base.material.asset_id,
    material_page_url: base.material.page_url,
    material_download_url: base.material.download_url,
    material_author: base.material.author,
    material_license_url: base.material.license_url,
    tts_status: base.tts_status,
    audio_public_url: base.audio_public_url,
    creatomate_render_id: render.id || '',
    creatomate_status: render.status || '',
    video_url: render.url || '',
    snapshot_url: render.snapshot_url || '',
    video_status: videoStatus,
    review_status: reviewStatus,
    publish_status: '未发布',
    remarks: remarks.join(' '),
    manual_review_checklist: [
      '事实是否都有来源链接',
      '来源是否可信且能打开',
      '素材是否来自Pexels/Pixabay并记录授权链接',
      '标题/字幕/口播/封面是否无站外联系方式',
      '配音是否自然',
      '视频是否1080x1920竖版',
      '是否适合人工发布'
    ].join('\n')
  }
}];
